window.allTests["klasik_u2_hukuk_3"] = [
    {
        soru: "<i>Ur-Nammu Kanunları, Sümer Tabletleri (MÖ 2100)<br>\"Eğer bir adam, bir başka adamın kemiğini bir silahla kırarsa, 1 mina gümüş ödeyecektir. Eğer bir adam başka bir adamın burnunu keserse, gümüşün üçte ikisini ödeyecektir.\"</i><br><br><b>Tarihin bilinen en eski yazılı kanunu olan Ur-Nammu kanunlarında cezalandırma yöntemi olarak hangi hukuki ilke benimsenmiştir? Bu ilkenin kan davalarını önlemedeki işlevi nedir?</b>",
        cevap: "Ur-Nammu kanunlarında 'Tazminat (bedel ödeme)' ilkesi benimsenmiştir. Suçun karşılığının fiziksel şiddet (kısas) yerine maddi bir değere bağlanması, şiddet döngüsünü kırarak toplumsal barışı korumayı sağlamıştır."
    },
    {
        soru: "<i>Hammurabi Kanunları, Dikilitaş Giriş Metni<br>\"Ülkede adaleti parlatmak, kötüleri yok etmek, güçlünün zayıfı ezmesini önlemek için Babil'in baş tanrısı Marduk ve Adalet Tanrısı Şamaş beni, Hammurabi'yi görevlendirdi.\"</i><br><br><b>Hammurabi, kanunlarının gücünü hangi kaynağa dayandırmaktadır? Bu durumun yasalara itaat üzerindeki etkisi ne olmuştur?</b>",
        cevap: "Gücünü Tanrılara (ilahi/teokratik kaynağa) dayandırmıştır. Yasaları çiğnemenin doğrudan tanrıya karşı gelmek (günah) sayılması, halkın yasalara sorgusuz sualsiz itaat etmesini kolaylaştırmıştır."
    },
    {
        soru: "<i>On İki Levha Kanunları, Roma (MÖ 451)<br>\"Pleplerin (sıradan halkın) uzun süren isyanları sonucunda, sadece Patricilerin (soyluların) bildiği ve uyguladığı sözlü gelenekler, on iki tunç levhaya yazılarak Forum meydanına asıldı.\"</i><br><br><b>Kanunların sözlü olmaktan çıkıp 'yazılı ve herkesin görebileceği (aleni)' hale gelmesinin sıradan halk açısından en büyük kazanımı nedir?</b>",
        cevap: "Soylu yargıçların kanunları kendi çıkarlarına göre keyfi olarak değiştirmesi ve yorumlaması engellenmiştir. Halk, haklarını öğrenmiş ve yasal güvenceye kavuşmuştur."
    },
    {
        soru: "<i>Christian Jacq, Mısır'ın Işığı (Tarihi Roman)<br>\"Mısır'da Mezopotamya'daki gibi uzun kanun maddelerine pek ihtiyaç yoktu. Çünkü Firavun'un ağzından çıkan her söz zaten ilahi evrensel uyumu (Ma'at) temsil eden tartışılmaz bir kanundu.\"</i><br><br><b>Eski Mısır'da gelişmiş yazılı kanunnamelerin ortaya çıkmamasının temelindeki siyasi ve dini inanç nedir?</b>",
        cevap: "Firavunun yeryüzündeki canlı bir tanrı olarak görülmesi ve sözlerinin mutlak yasa sayılmasıdır. Bu 'Tanrı-Kral' inancı, sabit yazılı kanunlara duyulan ihtiyacı ortadan kaldırmıştır."
    },
    {
        soru: "<i>Eski Ahit, Çıkış (Exodus) Bölümü<br>\"Sina Dağı'nda Tanrı Yahve, Musa'ya taş tabletler verdi. Üzerinde şöyle yazıyordu: 'Öldürmeyeceksin. Çalmayacaksın. Yalan yere tanıklık etmeyeceksin.'\"</i><br><br><b>İbrani hukukunun temelini oluşturan On Emir'in Mezopotamya kanunlarından (örneğin Hammurabi'den) kaynağı bakımından farkı nedir?</b>",
        cevap: "Hammurabi bir kralın tanrıdan yetki alarak oluşturduğu kanunlarken; On Emir doğrudan doğruya Tanrı'nın sözü (vahiy) olarak kabul edilen bir ilahi/dini hukuk (şeriat) sistemidir."
    },
    {
        soru: "<i>Aristoteles, Atina Anayasası<br>\"Drakon'un kanunları o kadar acımasızdı ki, bir meyve çalmanın cezası ile cinayetin cezası aynıydı: Ölüm. İnsanlar bu yasaların mürekkeple değil kanla yazıldığını söylerdi.\"</i><br><br><b>Drakon'un tüm suçlara ölüm cezası vermesinin amacı ne olabilir ve neden toplumsal düzensizliği çözmede başarısız olmuştur?</b>",
        cevap: "Amacı aşırı korku yaratarak suçu bitirmektir. Başarısız olmuştur çünkü suçun ağırlığı ile verilen ceza arasında bir adalet (orantı) olmadığı için halkın vicdanını yaralamış ve isyanlara yol açmıştır."
    },
    {
        soru: "<i>Frigya Tarihi İncelemeleri<br>\"Anadolu'da kurulan Frig devletinde, bilerek bir saban kırmanın veya bir öküzü öldürmenin cezası idamdı.\"</i><br><br><b>Sadece bir tarım aletine veya hayvanına zarar vermenin cezasının ölüm olması, Friglerin ekonomisi ile hukuku arasındaki ilişki nasıl açıklar?</b>",
        cevap: "Hukuk kuralları doğrudan devletin ekonomik temelini korumak için şekillenmiştir. Frig ekonomisi tamamen tarıma dayandığı için, tarıma verilen zarar devlete verilmiş bir zarar sayılarak en ağır şekilde cezalandırılmıştır."
    },
    {
        soru: "<i>Hammurabi Kanunları, Madde 196 ve 199<br>\"Eğer bir soylu, başka bir soylunun gözünü çıkarırsa, onun da gözü çıkarılır. Ancak bir soylu, bir kölenin gözünü çıkarırsa sadece kölenin değerinin yarısını öder.\"</i><br><br><b>Bu iki maddeyi karşılaştırdığınızda, Hammurabi Kanunları'nın 'Eşitlik' ilkesine bakış açısı hakkında ne söyleyebilirsiniz?</b>",
        cevap: "Kanunların eşitlikçi olmadığını, cezaların toplumdaki sınıf farklılıklarına (soylu, hür, köle) göre şekillendiğini gösterir. Köleye karşı işlenen suçlar, insana değil 'mala zarar verme' olarak değerlendirilmiştir."
    },
    {
        soru: "<i>Hitit Kanunları, Madde 4<br>\"Eğer bir adam, birini döverek öldürürse ve bu olay bir kavgada öfkeyle (istemeden) meydana gelmişse, ölenin ailesine 2 kişi (köle) verir ve yakası bırakılır.\"</i><br><br><b>Bu Hitit yasasına göre ceza verilirken suçlunun hangi durumu (niyeti) dikkate alınmaktadır? Bu durumun Mezopotamya'daki katı kısas anlayışından farkı nedir?</b>",
        cevap: "Suçun kasıtlı (planlı) mı yoksa kazara/öfke anında mı işlendiği (failin niyeti) dikkate alınmaktadır. Hitit hukuku, körü körüne kısas uygulamak yerine olayın içyüzünü sorgulayan daha insancıl ve gelişmiş bir yapıdadır."
    },
    {
        soru: "<i>Solon Kanunları, Atina (MÖ 594)<br>\"Solon, borcunu ödeyemediği için soylulara köle olan Atinalı vatandaşların borçlarını sildi ve borç karşılığı vatandaşların köle yapılmasını (Seisachtheia) kesin olarak yasakladı.\"</i><br><br><b>Solon'un 'borç köleliğini' kaldırması Atina'daki demokrasi ve siyasi katılım açısından neden hayati bir adımdır?</b>",
        cevap: "Özgür vatandaşların köleleşip seçme-seçilme haklarını kaybetmelerini önlemiştir. Halk meclisine (Ekklesia) katılabilecek özgür yurttaş sayısını koruyarak demokrasinin çökmesine engel olmuştur."
    }
];